// Time:  O(n)
// Space: O(1)

class Solution {
public:
    string reverseOnlyLetters(string S) {
        string result;
        int i = S.length() - 1;
        for (const auto& c : S) {
            if (isalpha(c)) {
                while (!isalpha(S[i])) {
                    --i;
                }
                result.push_back(S[i]);
                --i;
            } else {
                result.push_back(c);
            }
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(1)

class Solution(object):
    def reverseOnlyLetters(self, S):
        """
        :type S: str
        :rtype: str
        """
        def getNext(S):
            for i in reversed(xrange(len(S))):
                if S[i].isalpha():
                    yield S[i]

        result = []
        letter = getNext(S)
        for i in xrange(len(S)):
            if S[i].isalpha():
                result.append(letter.next())
            else:
                result.append(S[i])
        return "".join(result)
